import { type Href } from 'expo-router';
import { Text, View } from 'react-native';

import { useKangurMobileI18n } from '../i18n/kangurMobileI18n';
import type { KangurMobileLessonCheckpointItem } from '../lessons/useKangurMobileLessonCheckpoints';
import { createKangurPlanHref } from '../plan/planHref';
import { formatKangurMobileScoreDateTime } from '../scores/mobileScoreSummary';
import {
  KangurMobileInsetPanel as InsetPanel,
  KangurMobileLinkButton as LinkButton,
  KangurMobileMutedActionChip as MutedActionChip,
  KangurMobilePill as Pill,
  type KangurMobileTone as Tone,
} from '../shared/KangurMobileUi';
import { translateKangurMobileActionLabel } from '../shared/translateKangurMobileActionLabel';
import {
  type KangurMobileLeaderboardAssignmentItem,
} from './useKangurMobileLeaderboardAssignments';
import {
  type KangurMobileLeaderboardLessonMasteryItem,
} from './useKangurMobileLeaderboardLessonMastery';
import {
  type KangurMobileLeaderboardBadgeItem,
} from './useKangurMobileLeaderboardBadges';

export const FILTER_SCROLL_STYLE = {
  gap: 8,
  paddingBottom: 4,
} as const;

export const LESSONS_ROUTE = '/lessons' as Href;
export const PLAN_ROUTE = createKangurPlanHref();
export const PROFILE_ROUTE = '/profile' as Href;

export function LessonCheckpointRow({
  item,
}: {
  item: KangurMobileLessonCheckpointItem;
}): React.JSX.Element {
  const { copy, locale } = useKangurMobileI18n();
  const practiceAction = item.practiceHref ? (
    <LinkButton
      href={item.practiceHref}
      label={`${copy({
        de: 'Danach trainieren',
        en: 'Practice after',
        pl: 'Potem trenuj',
      })}: ${item.title}`}
    />
  ) : null;

  return (
    <InsetPanel gap={10}>
      <View
        style={{
          flexDirection: 'row',
          justifyContent: 'space-between',
          alignItems: 'flex-start',
          gap: 12,
        }}
      >
        <View style={{ flex: 1, gap: 4 }}>
          <Text style={{ color: '#0f172a', fontSize: 16, fontWeight: '800' }}>
            {item.emoji} {item.title}
          </Text>
          <Text style={{ color: '#475569', fontSize: 14, lineHeight: 20 }}>
            {copy({
              de: `Letztes Ergebnis ${item.lastScorePercent}% • Beherrschung ${item.masteryPercent}%`,
              en: `Last score ${item.lastScorePercent}% • mastery ${item.masteryPercent}%`,
              pl: `Ostatni wynik ${item.lastScorePercent}% • opanowanie ${item.masteryPercent}%`,
            })}
          </Text>
        </View>
        <Pill
          label={`${item.bestScorePercent}%`}
          tone={{
            backgroundColor: '#eef2ff',
            borderColor: '#c7d2fe',
            textColor: '#4338ca',
          }}
        />
      </View>

      <Text style={{ color: '#64748b', fontSize: 12, lineHeight: 18 }}>
        {copy({
          de: `Zuletzt gespeichert ${formatKangurMobileScoreDateTime(item.lastCompletedAt, locale)}`,
          en: `Last saved ${formatKangurMobileScoreDateTime(item.lastCompletedAt, locale)}`,
          pl: `Ostatni zapis ${formatKangurMobileScoreDateTime(item.lastCompletedAt, locale)}`,
        })}
      </Text>

      <View style={{ flexDirection: 'row', flexWrap: 'wrap', gap: 8 }}>
        <LinkButton
          href={item.lessonHref}
          label={`${copy({
            de: 'Zur Lektion zurück',
            en: 'Return to lesson',
            pl: 'Wróć do lekcji',
          })}: ${item.title}`}
          tone='primary'
        />
        {practiceAction}
      </View>
    </InsetPanel>
  );
}

export function LeaderboardAssignmentRow({
  item,
}: {
  item: KangurMobileLeaderboardAssignmentItem;
}): React.JSX.Element {
  const { copy, locale } = useKangurMobileI18n();
  const priorityTone =
    item.assignment.priority === 'high'
      ? {
          backgroundColor: '#fef2f2',
          borderColor: '#fecaca',
          textColor: '#b91c1c',
        }
      : item.assignment.priority === 'medium'
        ? {
            backgroundColor: '#fffbeb',
            borderColor: '#fde68a',
            textColor: '#b45309',
          }
        : {
            backgroundColor: '#eff6ff',
            borderColor: '#bfdbfe',
            textColor: '#1d4ed8',
          };
  const assignmentActionLabel = translateKangurMobileActionLabel(item.assignment.action.label, locale);
  const assignmentAction = item.href ? (
    <LinkButton href={item.href} label={assignmentActionLabel} tone='primary' />
  ) : (
    <MutedActionChip
      compact
      label={`${assignmentActionLabel} · ${copy({
        de: 'bald',
        en: 'soon',
        pl: 'wkrotce',
      })}`}
    />
  );

  return (
    <InsetPanel gap={8}>
      <Pill
        label={copy({
          de:
            item.assignment.priority === 'high'
              ? 'Hohe Priorität'
              : item.assignment.priority === 'medium'
                ? 'Mittlere Priorität'
                : 'Niedrige Priorität',
          en:
            item.assignment.priority === 'high'
              ? 'High priority'
              : item.assignment.priority === 'medium'
                ? 'Medium priority'
                : 'Low priority',
          pl:
            item.assignment.priority === 'high'
              ? 'Priorytet wysoki'
              : item.assignment.priority === 'medium'
                ? 'Priorytet średni'
                : 'Priorytet niski',
        })}
        tone={priorityTone}
      />

      <Text style={{ color: '#0f172a', fontSize: 16, fontWeight: '800' }}>
        {item.assignment.title}
      </Text>
      <Text style={{ color: '#475569', fontSize: 14, lineHeight: 20 }}>
        {item.assignment.description}
      </Text>
      <Text style={{ color: '#64748b', fontSize: 12, lineHeight: 18 }}>
        {copy({
          de: `Ziel: ${item.assignment.target}`,
          en: `Goal: ${item.assignment.target}`,
          pl: `Cel: ${item.assignment.target}`,
        })}
      </Text>

      {assignmentAction}
    </InsetPanel>
  );
}

export function LeaderboardBadgeChip({
  item,
}: {
  item: KangurMobileLeaderboardBadgeItem;
}): React.JSX.Element {
  return (
    <Pill
      label={`${item.emoji} ${item.name}`}
      tone={{
        backgroundColor: '#eef2ff',
        borderColor: '#c7d2fe',
        textColor: '#4338ca',
      }}
    />
  );
}

const getMasteryTone = (masteryPercent: number): Tone => {
  if (masteryPercent >= 90) {
    return {
      backgroundColor: '#ecfdf5',
      borderColor: '#a7f3d0',
      textColor: '#047857',
    };
  }
  if (masteryPercent >= 70) {
    return {
      backgroundColor: '#fffbeb',
      borderColor: '#fde68a',
      textColor: '#b45309',
    };
  }
  return {
    backgroundColor: '#fef2f2',
    borderColor: '#fecaca',
    textColor: '#b91c1c',
  };
};

function renderLeaderboardPracticeLink({
  href,
  label,
}: {
  href: Href | null;
  label: string;
}): React.JSX.Element | null {
  if (!href) {
    return null;
  }

  return <LinkButton href={href} label={label} />;
}

export function LessonMasteryRow({
  insight,
  title,
}: {
  insight: KangurMobileLeaderboardLessonMasteryItem;
  title: string;
}): React.JSX.Element {
  const { copy, locale } = useKangurMobileI18n();
  const masteryTone = getMasteryTone(insight.masteryPercent);
  const lastAttemptLabel = insight.lastCompletedAt
    ? formatKangurMobileScoreDateTime(insight.lastCompletedAt, locale)
    : copy({
        de: 'kein Datum',
        en: 'no date',
        pl: 'brak daty',
      });

  return (
    <InsetPanel gap={10}>
      <View
        style={{
          flexDirection: 'row',
          justifyContent: 'space-between',
          alignItems: 'flex-start',
          gap: 12,
        }}
      >
        <View style={{ flex: 1, gap: 4 }}>
          <Text style={{ color: '#64748b', fontSize: 12, fontWeight: '700' }}>{title}</Text>
          <Text style={{ color: '#0f172a', fontSize: 16, fontWeight: '800' }}>
            {insight.emoji} {insight.title}
          </Text>
          <Text style={{ color: '#475569', fontSize: 13, lineHeight: 18 }}>
            {copy({
              de: `Versuche ${insight.attempts} • letztes Ergebnis ${insight.lastScorePercent}%`,
              en: `Attempts ${insight.attempts} • last score ${insight.lastScorePercent}%`,
              pl: `Próby ${insight.attempts} • ostatni wynik ${insight.lastScorePercent}%`,
            })}
          </Text>
        </View>
        <Pill label={`${insight.masteryPercent}%`} tone={masteryTone} />
      </View>

      <Text style={{ color: '#64748b', fontSize: 12, lineHeight: 18 }}>
        {copy({
          de: `Bestes Ergebnis ${insight.bestScorePercent}% • letzter Versuch ${lastAttemptLabel}`,
          en: `Best score ${insight.bestScorePercent}% • last attempt ${lastAttemptLabel}`,
          pl: `Najlepszy wynik ${insight.bestScorePercent}% • ostatnia próba ${lastAttemptLabel}`,
        })}
      </Text>

      <View style={{ flexDirection: 'row', flexWrap: 'wrap', gap: 8 }}>
        <LinkButton
          href={insight.lessonHref}
          label={copy({
            de: 'Lektion öffnen',
            en: 'Open lesson',
            pl: 'Otwórz lekcję',
          })}
          tone='primary'
        />
        {renderLeaderboardPracticeLink({
          href: insight.practiceHref,
          label: copy({
            de: 'Danach trainieren',
            en: 'Practice after',
            pl: 'Potem trenuj',
          }),
        })}
      </View>
    </InsetPanel>
  );
}

import { Text, View } from 'react-native';
import {
  KangurMobileActionButton as ActionButton,
  KangurMobileCard as Card,
  KangurMobileInsetPanel as InsetPanel,
  KangurMobileLinkButton as LinkButton,
  KangurMobilePendingActionButton,
  KangurMobilePill as Pill,
} from '../../shared/KangurMobileUi';
import { DUELS_ROUTE } from '../daily-plan-primitives';
import { type KangurMobileCopy } from '../../i18n/kangurMobileI18n';
import { formatKangurMobileScoreDateTime } from '../../scores/mobileScoreSummary';
import {
  type KangurDuelOpponentEntry,
  type KangurDuelLeaderboardEntry,
} from 'packages/kangur-contracts/src/kangur-duels';

interface DailyPlanDuelsState {
  opponents: KangurDuelOpponentEntry[];
  currentRank: number | null;
  currentEntry: KangurDuelLeaderboardEntry | null;
  isRestoringAuth: boolean;
  isLoading: boolean;
  isAuthenticated: boolean;
  error: string | null;
  actionError: string | null;
  pendingOpponentLearnerId: string | null;
  refresh: () => void;
  createRematch: (learnerId: string) => Promise<string | null>;
}

interface DailyPlanDuelsSectionProps {
  copy: KangurMobileCopy;
  locale: string;
  duelPlan: DailyPlanDuelsState;
  openDuelSession: (sessionId: string) => void;
}

function isDuelLeaderboardEntry(entry: unknown): entry is KangurDuelLeaderboardEntry {
  return (
    typeof entry === 'object' &&
    entry !== null &&
    'learnerId' in entry &&
    'displayName' in entry &&
    'wins' in entry &&
    'losses' in entry &&
    'ties' in entry
  );
}

function OpponentItem({
  opponent,
  copy,
  locale,
  duelPlan,
  openDuelSession,
}: {
  opponent: KangurDuelOpponentEntry;
  copy: DailyPlanDuelsSectionProps['copy'];
  locale: string;
  duelPlan: DailyPlanDuelsState;
  openDuelSession: (sessionId: string) => void;
}): JSX.Element {
  return (
    <InsetPanel gap={8}>
      <Text style={{ color: '#0f172a', fontSize: 16, fontWeight: '800' }}>{opponent.displayName}</Text>
      <Text style={{ color: '#64748b', fontSize: 12, lineHeight: 18 }}>
        {copy({
          de: `Letztes Duell ${formatKangurMobileScoreDateTime(opponent.lastPlayedAt, locale)}`,
          en: `Last duel ${formatKangurMobileScoreDateTime(opponent.lastPlayedAt, locale)}`,
          pl: `Ostatni pojedynek ${formatKangurMobileScoreDateTime(opponent.lastPlayedAt, locale)}`,
        })}
      </Text>
      <KangurMobilePendingActionButton
        horizontalPadding={14}
        label={copy({ de: 'Schneller Rückkampf', en: 'Quick rematch', pl: 'Szybki rewanż' })}
        onPress={() => {
          void duelPlan.createRematch(opponent.learnerId).then((sessionId) => {
            if (sessionId !== null && sessionId !== '') openDuelSession(sessionId);
          });
        }}
        pending={duelPlan.pendingOpponentLearnerId === opponent.learnerId}
        pendingLabel={copy({ de: 'Rückkampf wird gesendet...', en: 'Sending rematch...', pl: 'Wysyłanie rewanżu...' })}
      />
    </InsetPanel>
  );
}

function CurrentEntryPanel({
  copy,
  rank,
  entry,
}: {
  copy: DailyPlanDuelsSectionProps['copy'];
  rank: number | null;
  entry: KangurDuelLeaderboardEntry;
}): JSX.Element {
  return (
    <InsetPanel gap={8} style={{ borderColor: '#bfdbfe', backgroundColor: '#eff6ff' }}>
      <Text style={{ color: '#1d4ed8', fontSize: 12, fontWeight: '800' }}>
        {copy({ de: 'DEIN DUELLSTAND', en: 'YOUR DUEL SNAPSHOT', pl: 'TWÓJ WYNIK W POJEDYNKACH' })}
      </Text>
      <Text style={{ color: '#0f172a', fontSize: 18, fontWeight: '800' }}>
        #{rank ?? 0} {entry.displayName}
      </Text>
      <Text style={{ color: '#475569', fontSize: 14, lineHeight: 20 }}>
        {copy({
          de: `Siege ${entry.wins} • Niederlagen ${entry.losses} • Unentschieden ${entry.ties}`,
          en: `Wins ${entry.wins} • Losses ${entry.losses} • Ties ${entry.ties}`,
          pl: `Wygrane ${entry.wins} • Porażki ${entry.losses} • Remisy ${entry.ties}`,
        })}
      </Text>
    </InsetPanel>
  );
}

function DailyPlanDuelsLoading({ copy }: { copy: DailyPlanDuelsSectionProps['copy'] }): JSX.Element {
  return (
    <Card>
      <Text style={{ color: '#475569', lineHeight: 22 }}>
        {copy({
          de: 'Der heutige Duellstand wird geladen...',
          en: 'Loading today’s duel standing...',
          pl: 'Ładujemy dzisiejszy stan pojedynków...',
        })}
      </Text>
    </Card>
  );
}

function DailyPlanDuelsUnauthenticated({ copy }: { copy: DailyPlanDuelsSectionProps['copy'] }): JSX.Element {
  return (
    <Card>
      <Text style={{ color: '#475569', lineHeight: 22 }}>
        {copy({
          de: 'Melde dich an, um hier deinen Duellstand, letzte Rivalen und schnelle Rückkämpfe zu sehen.',
          en: 'Sign in to see duel standing, recent rivals, and quick rematches here.',
          pl: 'Zaloguj się, aby zobaczyć tutaj stan w pojedynkach, ostatnich rywali i szybkie rewanże.',
        })}
      </Text>
    </Card>
  );
}

function DailyPlanDuelsError({
  error,
  copy,
  onRefresh,
}: {
  error: string;
  copy: DailyPlanDuelsSectionProps['copy'];
  onRefresh: () => void;
}): JSX.Element {
  return (
    <Card>
      <View style={{ gap: 10 }}>
        <Text style={{ color: '#b91c1c', lineHeight: 20 }}>{error}</Text>
        <ActionButton label={copy({ de: 'Duelle aktualisieren', en: 'Refresh duels', pl: 'Odśwież pojedynki' })} onPress={onRefresh} />
      </View>
    </Card>
  );
}

function DailyPlanDuelsBody({
  copy,
  locale,
  duelPlan,
  openDuelSession,
  opponents,
  currentRank,
  currentEntry,
  actionError,
}: {
  copy: DailyPlanDuelsSectionProps['copy'];
  locale: string;
  duelPlan: DailyPlanDuelsState;
  openDuelSession: (sessionId: string) => void;
  opponents: KangurDuelOpponentEntry[];
  currentRank: number | null;
  currentEntry: KangurDuelLeaderboardEntry | null;
  actionError: string | null;
}): JSX.Element {
  return (
    <Card>
      <View style={{ gap: 4 }}>
        <Text style={{ color: '#64748b', fontSize: 12, fontWeight: '700' }}>
          {copy({ de: 'Duelle für heute', en: 'Duels for today', pl: 'Pojedynki na dziś' })}
        </Text>
        <Text style={{ color: '#0f172a', fontSize: 20, fontWeight: '800' }}>
          {copy({ de: 'Schneller Rückweg zu Rivalen', en: 'Quick return to rivals', pl: 'Szybki powrót do rywali' })}
        </Text>
      </View>

      <View style={{ flexDirection: 'row', flexWrap: 'wrap', gap: 8 }}>
        <Pill
          label={copy({
            de: `Rivalen ${opponents.length}`,
            en: `Rivals ${opponents.length}`,
            pl: `Rywale ${opponents.length}`,
          })}
          tone={{ backgroundColor: '#eef2ff', borderColor: '#c7d2fe', textColor: '#4338ca' }}
        />
        <Pill
          label={
            currentRank !== null && currentRank !== 0
              ? copy({
                  de: `Deine Position #${currentRank}`,
                  en: `Your rank #${currentRank}`,
                  pl: `Twoja pozycja #${currentRank}`,
                })
              : copy({ de: 'Wartet auf Sichtbarkeit', en: 'Waiting for visibility', pl: 'Czeka na widoczność' })
          }
          tone={{ backgroundColor: '#ecfdf5', borderColor: '#a7f3d0', textColor: '#047857' }}
        />
      </View>

      <View style={{ gap: 12 }}>
        {isDuelLeaderboardEntry(currentEntry) ? (
          <CurrentEntryPanel copy={copy} rank={currentRank} entry={currentEntry} />
        ) : (
          <Text style={{ color: '#475569', lineHeight: 22 }}>
            {copy({
              de: 'Dein Konto ist in diesem Duellstand noch nicht sichtbar.',
              en: 'Your account is not visible in this duel standing yet.',
              pl: 'Twojego konta nie widać jeszcze w tym stanie pojedynków.',
            })}
          </Text>
        )}

        {actionError !== null && <Text style={{ color: '#b91c1c', lineHeight: 20 }}>{actionError}</Text>}

        {opponents.length === 0 ? (
          <Text style={{ color: '#475569', lineHeight: 22 }}>
            {copy({
              de: 'Es gibt noch keine letzten Rivalen.',
              en: 'There are no recent rivals yet.',
              pl: 'Nie ma jeszcze ostatnich rywali.',
            })}
          </Text>
        ) : (
          <View style={{ gap: 12 }}>
            {opponents.map((opponent) => (
              <OpponentItem
                key={opponent.learnerId}
                opponent={opponent}
                copy={copy}
                locale={locale}
                duelPlan={duelPlan}
                openDuelSession={openDuelSession}
              />
            ))}
          </View>
        )}

        <View style={{ alignSelf: 'stretch', gap: 10 }}>
          <ActionButton
            label={copy({ de: 'Duelle aktualisieren', en: 'Refresh duels', pl: 'Odśwież pojedynki' })}
            onPress={duelPlan.refresh}
            stretch
            tone='secondary'
          />
          <LinkButton
            href={DUELS_ROUTE}
            label={copy({ de: 'Duelle öffnen', en: 'Open duels', pl: 'Otwórz pojedynki' })}
            stretch
          />
        </View>
      </View>
    </Card>
  );
}

export function DailyPlanDuelsSection({
  copy,
  locale,
  duelPlan,
  openDuelSession,
}: DailyPlanDuelsSectionProps): JSX.Element {
  const { opponents, currentRank, currentEntry, isRestoringAuth, isLoading, isAuthenticated, error, actionError } =
    duelPlan;

  if (isRestoringAuth || isLoading) {
    return <DailyPlanDuelsLoading copy={copy} />;
  }

  if (!isAuthenticated) {
    return <DailyPlanDuelsUnauthenticated copy={copy} />;
  }

  if (error !== null) {
    return <DailyPlanDuelsError error={error} copy={copy} onRefresh={duelPlan.refresh} />;
  }

  return (
    <DailyPlanDuelsBody
      copy={copy}
      locale={locale}
      duelPlan={duelPlan}
      openDuelSession={openDuelSession}
      opponents={opponents}
      currentRank={currentRank}
      currentEntry={currentEntry}
      actionError={actionError}
    />
  );
}

import { Text, View } from 'react-native';
import { KangurMobileCard as Card, KangurMobileLinkButton as LinkButton } from '../../shared/KangurMobileUi';
import { RecentResultRow, RESULTS_ROUTE } from '../daily-plan-primitives';
import { type KangurMobileCopy } from '../../i18n/kangurMobileI18n';
import { createKangurResultsHref } from '../../scores/resultsHref';

interface DailyPlanResultsSectionProps {
    copy: KangurMobileCopy;
    isLoading: boolean;
    isAuthenticated: boolean;
    scoreError: string | null;
    recentResultItems: any[];
}

export function DailyPlanResultsSection({
    copy,
    isLoading,
    isAuthenticated,
    scoreError,
    recentResultItems,
}: DailyPlanResultsSectionProps): React.JSX.Element {
    return (
        <Card>
            <View style={{ flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center', gap: 12 }}>
                <Text style={{ color: '#0f172a', fontSize: 20, fontWeight: '800' }}>
                    {copy({ de: 'Ergebniszentrale', en: 'Results hub', pl: 'Centrum wyników' })}
                </Text>
                <LinkButton href={createKangurResultsHref()} label={copy({ de: 'Vollständigen Verlauf öffnen', en: 'Open full history', pl: 'Otwórz pełną historię' })} />
            </View>
            {isLoading ? (
                <Text style={{ color: '#475569' }}>
                    {copy({ de: 'Die letzten Ergebnisse werden geladen...', en: 'Loading recent results...', pl: 'Ładujemy ostatnie wyniki...' })}
                </Text>
            ) : !isAuthenticated ? (
                <Text style={{ color: '#475569', lineHeight: 22 }}>
                    {copy({ de: 'Melde dich an, um hier Ergebnisse zu sehen.', en: 'Sign in to see results here.', pl: 'Zaloguj się, aby zobaczyć tutaj wyniki.' })}
                </Text>
            ) : Boolean(scoreError) ? (
                <Text style={{ color: '#b91c1c', lineHeight: 20 }}>{scoreError}</Text>
            ) : recentResultItems.length === 0 ? (
                <Text style={{ color: '#475569', lineHeight: 22 }}>
                    {copy({ de: 'Es gibt hier noch keine Ergebnisse. Schließe einen Lauf ab, um diesen Bereich zu füllen.', en: 'There are no results here yet. Finish one run to fill this section.', pl: 'Nie ma tu jeszcze wyników. Ukończ jedną serię, aby wypełnić tę sekcję.' })}
                </Text>
            ) : (
                <View style={{ gap: 12 }}>
                    {recentResultItems.map(({ result, historyHref, lessonHref, practiceHref }) => (
                        <RecentResultRow key={result.id} result={result} historyHref={historyHref} lessonHref={lessonHref} practiceHref={practiceHref} />
                    ))}
                </View>
            )}
        </Card>
    );
}

import type { Href } from 'expo-router';
import { Text, View } from 'react-native';

import { useKangurMobileI18n } from '../i18n/kangurMobileI18n';
import {
  KangurMobileActionButton as ActionButton,
  KangurMobileCard as Card,
  KangurMobileInsetPanel as InsetPanel,
  KangurMobileLinkButton as LinkButton,
  KangurMobilePendingActionButton,
  KangurMobileSummaryChip,
} from '../shared/KangurMobileUi';
import { formatKangurMobileScoreDateTime } from './mobileScoreSummary';

type DuelCurrentEntry = {
  displayName: string;
  lastPlayedAt: string;
  losses: number;
  matches: number;
  ties: number;
  winRate: number;
  wins: number;
};

type DuelOpponent = {
  displayName: string;
  lastPlayedAt: string;
  learnerId: string;
};

export type ResultsDuelsState = {
  actionError: string | null;
  createRematch: (opponentLearnerId: string) => Promise<string | null>;
  currentEntry: DuelCurrentEntry | null;
  currentRank: number | null;
  error: string | null;
  isActionPending: boolean;
  isLoading: boolean;
  isRestoringAuth: boolean;
  opponents: DuelOpponent[];
  pendingOpponentLearnerId: string | null;
  refresh: () => Promise<void>;
};

function renderDuelStatus(duelResults: ResultsDuelsState, copy: any): React.JSX.Element | null {
  if (duelResults.isRestoringAuth || duelResults.isLoading) {
    return (
      <Text style={{ color: '#475569', fontSize: 14, lineHeight: 20 }}>
        {copy({
          de: 'Der Duellstand in den Ergebnissen wird geladen.',
          en: 'Loading the duel standing in results.',
          pl: 'Pobieramy stan pojedynków w wynikach.',
        })}
      </Text>
    );
  }
  if (duelResults.error) {
    return (
      <View style={{ gap: 10 }}>
        <Text style={{ color: '#b91c1c', fontSize: 14, lineHeight: 20 }}>
          {duelResults.error}
        </Text>
        <ActionButton
          label={copy({
            de: 'Duelle aktualisieren',
            en: 'Refresh duels',
            pl: 'Odśwież pojedynki',
          })}
          onPress={() => {
            void duelResults.refresh();
          }}
          stretch
          style={{ borderRadius: 16 }}
          tone='primary'
          verticalPadding={12}
        />
      </View>
    );
  }
  return null;
}

export function ResultsDuelsCard({
  duelResults,
  duelsHref,
  openDuelSession,
}: {
  duelResults: ResultsDuelsState;
  duelsHref: Href;
  openDuelSession: (sessionId: string) => void;
}): React.JSX.Element {
  const { copy, locale } = useKangurMobileI18n();

  return (
    <Card>
      <View style={{ gap: 4 }}>
        <Text style={{ color: '#64748b', fontSize: 12, fontWeight: '700' }}>
          {copy({
            de: 'Duelle',
            en: 'Duels',
            pl: 'Pojedynki',
          })}
        </Text>
        <Text style={{ color: '#0f172a', fontSize: 18, fontWeight: '800' }}>
          {copy({
            de: 'Schneller Rückweg zu Rivalen',
            en: 'Quick return to rivals',
            pl: 'Szybki powrót do rywali',
          })}
        </Text>
        <Text style={{ color: '#475569', fontSize: 14, lineHeight: 20 }}>
          {copy({
            de: 'Prüfe den aktuellen Duellstand, sieh die letzten Rivalen und starte einen Rückkampf, ohne Ergebnisse zu verlassen.',
            en: 'Check the current duel standing, see recent rivals, and jump into a rematch without leaving results.',
            pl: 'Sprawdź aktualny stan pojedynków, zobacz ostatnich rywali i wejdź w rewanż bez wychodzenia z wyników.',
          })}
        </Text>
      </View>

      <View style={{ flexDirection: 'row', flexWrap: 'wrap', gap: 8 }}>
        <KangurMobileSummaryChip
          label={copy({
            de: `Rivalen ${duelResults.opponents.length}`,
            en: `Rivals ${duelResults.opponents.length}`,
            pl: `Rywale ${duelResults.opponents.length}`,
          })}
          backgroundColor='#eff6ff'
          borderColor='#bfdbfe'
          textColor='#1d4ed8'
        />
        <KangurMobileSummaryChip
          label={
            duelResults.currentRank
              ? copy({
                  de: `Deine Position #${duelResults.currentRank}`,
                  en: `Your rank #${duelResults.currentRank}`,
                  pl: `Twoja pozycja #${duelResults.currentRank}`,
                })
              : copy({
                  de: 'Wartet auf Sichtbarkeit',
                  en: 'Waiting for visibility',
                  pl: 'Czeka na widoczność',
                })
          }
          backgroundColor='#ecfdf5'
          borderColor='#a7f3d0'
          textColor='#047857'
        />
      </View>

      {renderDuelStatus(duelResults, copy)}

      {duelResults.currentRank !== null && duelResults.currentEntry ? (
        <InsetPanel
          gap={10}
          tone={{
            borderColor: '#bfdbfe',
            backgroundColor: '#eff6ff',
          }}
        >
          <Text style={{ color: '#1d4ed8', fontSize: 12, fontWeight: '800' }}>
            {copy({
              de: 'DEIN DUELLSTAND',
              en: 'YOUR DUEL SNAPSHOT',
              pl: 'TWÓJ WYNIK W POJEDYNKACH',
            })}
          </Text>
          <Text style={{ color: '#0f172a', fontSize: 18, fontWeight: '800' }}>
            #{duelResults.currentRank} {duelResults.currentEntry.displayName}
          </Text>
          <Text style={{ color: '#475569', fontSize: 14, lineHeight: 20 }}>
            {copy({
              de: `Siege ${duelResults.currentEntry.wins} • Niederlagen ${duelResults.currentEntry.losses} • Unentschieden ${duelResults.currentEntry.ties}`,
              en: `Wins ${duelResults.currentEntry.wins} • Losses ${duelResults.currentEntry.losses} • Ties ${duelResults.currentEntry.ties}`,
              pl: `Wygrane ${duelResults.currentEntry.wins} • Porażki ${duelResults.currentEntry.losses} • Remisy ${duelResults.currentEntry.ties}`,
            })}
          </Text>
          <Text style={{ color: '#64748b', fontSize: 12, lineHeight: 18 }}>
            {copy({
              de: `Matches ${duelResults.currentEntry.matches} • Quote ${Math.round(duelResults.currentEntry.winRate * 100)}% • letztes Duell ${formatKangurMobileScoreDateTime(duelResults.currentEntry.lastPlayedAt, locale)}`,
              en: `Matches ${duelResults.currentEntry.matches} • Win rate ${Math.round(duelResults.currentEntry.winRate * 100)}% • last duel ${formatKangurMobileScoreDateTime(duelResults.currentEntry.lastPlayedAt, locale)}`,
              pl: `Mecze ${duelResults.currentEntry.matches} • Win rate ${Math.round(duelResults.currentEntry.winRate * 100)}% • ostatni pojedynek ${formatKangurMobileScoreDateTime(duelResults.currentEntry.lastPlayedAt, locale)}`,
            })}
          </Text>
        </InsetPanel>
      ) : (
        <RenderResultsContent copy={copy} />
      )}

      {duelResults.actionError ? (
        <Text style={{ color: '#b91c1c', fontSize: 14, lineHeight: 20 }}>
          {duelResults.actionError}
        </Text>
      ) : null}

      {duelResults.opponents.length === 0 ? (
        <Text style={{ color: '#475569', fontSize: 14, lineHeight: 20 }}>
          {copy({
            de: 'Es gibt noch keine letzten Rivalen. Das erste beendete Duell füllt hier die Rivalenliste und schaltet schnelle Rückkämpfe frei.',
            en: 'There are no recent rivals yet. The first completed duel will fill the rival list here and unlock quick rematches.',
            pl: 'Nie ma jeszcze ostatnich rywali. Pierwszy zakończony pojedynek wypełni tutaj listę rywali i odblokuje szybkie rewanże.',
          })}
        </Text>
      ) : (
        <View style={{ gap: 10 }}>
          <Text style={{ color: '#0f172a', fontSize: 15, fontWeight: '800' }}>
            {copy({
              de: 'Letzte Rivalen',
              en: 'Recent rivals',
              pl: 'Ostatni rywale',
            })}
          </Text>
          {duelResults.opponents.map((opponent) => (
            <InsetPanel
              key={opponent.learnerId}
              gap={8}
            >
              <Text style={{ color: '#0f172a', fontSize: 16, fontWeight: '800' }}>
                {opponent.displayName}
              </Text>
              <Text style={{ color: '#64748b', fontSize: 12, lineHeight: 18 }}>
                {copy({
                  de: `Letztes Duell ${formatKangurMobileScoreDateTime(opponent.lastPlayedAt, locale)}`,
                  en: `Last duel ${formatKangurMobileScoreDateTime(opponent.lastPlayedAt, locale)}`,
                  pl: `Ostatni pojedynek ${formatKangurMobileScoreDateTime(opponent.lastPlayedAt, locale)}`,
                })}
              </Text>
              <KangurMobilePendingActionButton
                horizontalPadding={14}
                label={copy({
                  de: 'Schneller Rückkampf',
                  en: 'Quick rematch',
                  pl: 'Szybki rewanż',
                })}
                onPress={() => {
                  void duelResults.createRematch(opponent.learnerId).then((sessionId) => {
                    if (sessionId) {
                      openDuelSession(sessionId);
                    }
                  });
                }}
                pending={duelResults.pendingOpponentLearnerId === opponent.learnerId}
                pendingLabel={copy({
                  de: 'Rückkampf wird gesendet...',
                  en: 'Sending rematch...',
                  pl: 'Wysyłanie rewanżu...',
                })}
              />
            </InsetPanel>
          ))}
        </View>
      )}

      <View style={{ alignSelf: 'stretch', gap: 10 }}>
        <ActionButton
          label={copy({
            de: 'Duelle aktualisieren',
            en: 'Refresh duels',
            pl: 'Odśwież pojedynki',
          })}
          onPress={() => {
            void duelResults.refresh();
          }}
          stretch
          tone='secondary'
        />

        <LinkButton
          href={duelsHref}
          label={copy({
            de: 'Duelle öffnen',
            en: 'Open duels',
            pl: 'Otwórz pojedynki',
          })}
          stretch
        />
      </View>
    </Card>
  );
}

function RenderResultsContent({ copy }: { copy: any }): React.JSX.Element {
  return (
    <Text style={{ color: '#475569', fontSize: 14, lineHeight: 20 }}>
      {copy({
        de: 'Dein Konto ist in diesem Duellstand noch nicht sichtbar. Schließe ein weiteres Duell ab oder öffne die Lobby, damit deine Position hier erscheint.',
        en: 'Your account is not visible in this duel standing yet. Finish another duel or open the lobby so your rank appears here.',
        pl: 'Twojego konta nie widać jeszcze w tym stanie pojedynków. Rozegraj kolejny pojedynek albo otwórz lobby, aby pojawiła się tutaj Twoja pozycja.',
      })}
    </Text>
  );
}
